mapper.select:
SELECT g.*, s.name AS student_name, s.student_no FROM student_grade g LEFT JOIN student s ON g.student_id = s.pk_student
AND g.student_id = #{studentId}
AND g.semester = #{semester}
AND g.course_name LIKE CONCAT('%', #{courseName}, '%')
ORDER BY g.semester DESC, g.course_name ASC

mapper.update:
UPDATE student_grade
semester = #{semester}, course_name = #{courseName}, course_type = #{courseType}, credit = #{credit}, score = #{score}, gpa = #{gpa},
WHERE pk_grade = #{pkGrade}
